scwin.sbm_search_submitdone = async function(e) {
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);
    if (rowCnt == 0) {
        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    } else {
        scwin.f_Rate();
        gr_master.setFocusedCell(0, "coNm");
    }
};

scwin.sbm_search_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_unit_submitdone = function(e) {
};

scwin.sbm_unit_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.lc_unit_onchange = function(e) {
    scwin.f_SetGridUnit();
};

scwin.trigger1_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.trigger2_onclick = function(e) {
    scwin.f_Retrieve();
};
